prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?elem ?name ?type ?comment WHERE {
  ?elem tai:normalizedId ?id .
  FILTER(CONTAINS(LCASE(STR(?id)), LCASE("f404135647444aedabe98bb54c000517")))
  ?elem a ?type .
  OPTIONAL { ?elem bbo:name ?name . }
  OPTIONAL { ?elem rdfs:comment ?comment . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?name ?origId ?normId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?name . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  FILTER(CONTAINS(LCASE(STR(?origId)), LCASE("f404135647444aedabe98bb54c000517")) || 
         CONTAINS(LCASE(STR(?normId)), LCASE("f404135647444aedabe98bb54c000517")))
}
LIMIT 25
